patch:
public Paint getPaint(double value) {
    if(this.upperBound <= this.lowerBound){
        throw new IllegalArgumentException("Upper bound must be greater than lower bound");
    }

    double normalizedValue;
    //Normalize input to range [0,1]
    if(value < this.lowerBound){
        normalizedValue = 0.0;
    }else if(value > this.upperBound){
        normalizedValue = 1.0;
    }else{
        normalizedValue = (value - this.lowerBound) / (this.upperBound - this.lowerBound);
    }

    int g = (int) (normalizedValue * 255.0);

    // Make sure that color components are within valid range [0,255]
    g = Math.max(g, 0);
    g = Math.min(g, 255);

    return new Color(g, g, g);
}

