patch:
protected void burstToken(String token, boolean stopAtNonOption) {
  int length = token.length();

  // loop through each char in token
  for (int i = 1; i < length; ++i) {
      final String ch = String.valueOf(token.charAt(i));

      // check if it's an option
      if (!options.hasOption(ch)) {
          // if stopAtNonOption is true and we encounter a non-option, process rest as argument
          if (stopAtNonOption && i > 1) {
              tokens.add(token.substring(0, i));

              // call recursively on remaining arguments
              process(token.substring(i));

              return;
          }

          // if stopAtNonOption is false, add whole token as single argument
          tokens.add(token);

          return;
      }

      tokens.add("-" + ch);
      currentOption = options.getOption(ch);

      // if option has arg, append everything after this char
      if (currentOption.hasArg() && i + 1 < length) {
          tokens.add(token.substring(i + 1));

          break;
      }
  }
}

