private void handleBlockComment(Comment comment) {
  String value = comment.getValue();
  boolean suspicious = false;

  // check for at least one JSDoc annotation
  int indexOfAtSign = value.indexOf('@');
  while (indexOfAtSign != -1 && indexOfAtSign < value.length() - 1) {
    char nextChar = value.charAt(indexOfAtSign + 1);
    if ((nextChar >= 'A' && nextChar <= 'Z') || (nextChar >= 'a' && nextChar <= 'z')) {
      suspicious = true;
      break;
    }
    indexOfAtSign = value.indexOf('@', indexOfAtSign + 1);
  }

  if (suspicious) {
    errorReporter.warning(SUSPICIOUS_COMMENT_WARNING, sourceName, comment.getLineno(), "", 0);
  }
}

