patch:
public static boolean equals(final CharSequence cs1, final CharSequence cs2) {
    if (cs1 == cs2) {
        return true;
    }
    if (cs1 == null || cs2 == null) {
        return false;
    }
    // check for equals between strings directly to avoid unnecessary regionMatch operation
    if (cs1 instanceof String && cs2 instanceof String) {
        return ((String)cs1).equals((String)cs2);
    }
    int len1 = cs1.length();
    int len2 = cs2.length();
    // If string's length are not same, they cannot be equal so returning false
    if (len1 != len2) {
        return false;
    }
    return CharSequenceUtils.regionMatches(cs1, false, 0, cs2, 0, len1);
}

