public <M extends Map<String, String>> M putIn(final M map) {
    // Return empty map instead of null for cases where there's no header available
    if (mapping == null || mapping.isEmpty()) {
        return map;
    }

    for (final Map.Entry<String, Integer> entry : mapping.entrySet()) {
        final int col = entry.getValue().intValue();

        if (col < values.length && values[col] != null) {
            map.put(entry.getKey(), values[col]);
        }
    }

    return map;
}

