patch:
public <T> MappingIterator<T> readValues(byte[] src, int offset, int length)
    throws IOException, JsonProcessingException
{
    byte[] subarray;
    if ((offset | length) < 0 || offset > src.length || length > src.length - offset) {
         throw new ArrayIndexOutOfBoundsException();
     } else if (offset == 0 && length == src.length) {
         // whole buffer used
         subarray = src;
     } else {
         // part of buffer used; create copy for sliced parsing
         subarray = new byte[length];
         System.arraycopy(src, offset, subarray, 0, length);
     }

    if (_dataFormatReaders != null) {
        return _detectBindAndReadValues(_dataFormatReaders.findFormat(subarray), false);
    }
    return _bindAndReadValues(_considerFilter(_parserFactory.createParser(subarray), 
            true));
}

