static boolean preserveWhitespace(Node node) {
    // check for the element and its parents all the way upto level 5
    int searchLevel = 0;
    while (node != null && node instanceof Element && searchLevel < 5) {
        Element el = (Element) node;
        if (el.tag.preserveWhitespace())
            return true;
        node = node.parent();
        searchLevel++;
    }
    return false;
}

