private static StringBuilder escapeRegex(StringBuilder regex, String value, boolean unquote) {
    int lastIndex = value.length() - 1;
    boolean wasWhite= false;
    for(int i= 0; i <= lastIndex; ++i) {
        char c= value.charAt(i);
        if(Character.isWhitespace(c)) {
            if(!wasWhite && i != lastIndex) { // avoid trailing spaces
                wasWhite= true;
                regex.append("\\s*");
            } else {
                regex.append(c);   // keep one leading or trailing space in original format
            }
            continue;
        }
        wasWhite= false;
        switch(c) {
        case '\'':
            if(unquote) {
                if(++i > lastIndex) {
                    return regex;
                }
                c= value.charAt(i);
            }
            break;
        case '?':
        case '[':
        case ']':
        case '(':
        case ')':
        case '{':
        case '}':
        case '\\':
        case '|':
        case '*':
        case '+':
        case '^':
        case '$':
        case '.':
            regex.append('\\');
