public static boolean equals(CharSequence cs1, CharSequence cs2) {
    // Check if both inputs are null or identical
    if (cs1 == cs2) {
        return true;
    }

    // If one input is null, but the other isn't, they can't be equal
    if (cs1 == null || cs2 == null) {
        return false;
    }

    // Length check could improve performance for short strings
    int length1 = cs1.length();
    int length2 = cs2.length();
    if (length1 != length2) {
        return false;
    }

    // Perform the comparison character by character
    for (int i = 0; i < length1; i++) {
        if (!(cs1.charAt(i) == cs2.charAt(i))) {
            return false;
        }
    }

    return true;
}

