private static int greatestCommonDivisor(long u, long v) {
    // From Commons Math:
    // if either operand is zero, return the other operand:
    if (u == 0 || v == 0) {
        return (int) (u + v);
    }
    // keep u and v negative, as they could be smaller than 2^31 (in Java, it is defined as integer in signed integer types)
    boolean posU = false, posV = false;
    if (u < 0) {
        u = -u;
        posU = true;
    }
    if (v < 0) {
        v = -v;
        posV = true;
    }
    // Find the common factors of 2 and continue with the rest
    int shift = 0;
    while ((u & 1) == 0 && (v & 1) == 0) { // while u and v are both even...
        u >>= 1; v >>= 1; ++shift; // divide them by 2.
    }
    // Here u and v are both odd or zero
    while ((u & 1) == 0) { // while u is even...
        u >>= 1; // divide it by 2
    }
    do {
        while((v & 1) == 0) { // while v is even...
          v >>= 1; // divide it by 2
        }
        // Now both u and v are odd
        if (u < v) {
           v -= u;
        } else {
           long diff = u - v;
           u = v;
           v = diff;
        }
    } while (v != 0);
    return (int)(u << shift); // gcd is u * 2^k
}

