private StringBuffer appendQuotedString(String pattern, ParsePosition pos,
        StringBuffer appendTo, boolean escapingOn) {
    int start = pos.getIndex();
    char[] c = pattern.toCharArray();
    if (escapingOn && c[start] == QUOTE) {
        next(pos);
        return appendTo == null ? null : appendTo.append(QUOTE);
    }
    int lastHold = start;
    while (pos.getIndex() < pattern.length()) {
        if (escapingOn && pattern.substring(pos.getIndex()).startsWith(ESCAPED_QUOTE)) {
            appendTo.append(c, lastHold, pos.getIndex() - lastHold).append(
                    QUOTE);
            pos.setIndex(pos.getIndex() + ESCAPED_QUOTE.length());
            lastHold = pos.getIndex();
            continue;
        } else if (pattern.charAt(pos.getIndex()) != QUOTE || (!escapingOn && pattern.charAt(pos.getIndex()-1)!='\\')){
            break;
        }
        next(pos);
    }

    if(pattern.charAt(pos.getIndex()-1)=='\\'&&pattern.charAt(pos.getIndex())==QUOTE){
        appendTo.append(c, lastHold, pos.getIndex() - lastHold+1);
    }else{
        appendTo.append(c, lastHold, pos.getIndex() - lastHold);
    }

    if (pos.getIndex() >= pattern.length()) {
        throw new IllegalArgumentException(
                "Unterminated quoted string at position " + start);
    }
    next(pos);
    return appendTo;
}

